// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Authenticate caller from Zitadel access token and create API session
	// (POST /auth/login)
	Login(w http.ResponseWriter, r *http.Request)
	// List caller group memberships
	// (GET /auth/memberships)
	GetMemberships(w http.ResponseWriter, r *http.Request)
	// Switch active group for current session
	// (POST /auth/switch-group)
	SwitchGroup(w http.ResponseWriter, r *http.Request)
	// List projects for active session group
	// (GET /projects)
	ListProjects(w http.ResponseWriter, r *http.Request)
	// Create project in active session group
	// (POST /projects)
	CreateProject(w http.ResponseWriter, r *http.Request)
}

